import pandas as pd
from datetime import datetime, timedelta
import sys
import argparse

# Mock data generator for demonstration (replace with actual API calls to QuickBooks/Sage)
def fetch_accounting_data(start_date, end_date):
    # Simulate fetching data from an accounting system
    # In a real scenario, use QuickBooks/Sage API or database queries
    dates = pd.date_range(start_date, end_date)
    data = {
        "date": dates,
        "revenue": [1000 + i * 50 for i in range(len(dates))],
        "expenses": [500 + i * 30 for i in range(len(dates))],
        "tax": [200 + i * 10 for i in range(len(dates))],
    }
    return pd.DataFrame(data)

def generate_report(data, report_type, period):
    report = {}

    if report_type == "income_statement":
        report["total_revenue"] = data["revenue"].sum()
        report["total_expenses"] = data["expenses"].sum()
        report["net_income"] = report["total_revenue"] - report["total_expenses"]

    elif report_type == "tax_summary":
        report["total_tax"] = data["tax"].sum()
        report["taxable_income"] = data["revenue"].sum() - data["expenses"].sum()

    elif report_type == "cash_flow":
        report["cash_in"] = data["revenue"].sum()
        report["cash_out"] = data["expenses"].sum() + data["tax"].sum()
        report["net_cash_flow"] = report["cash_in"] - report["cash_out"]

    report["period"] = period
    report["generated_on"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")

    return report

def save_report(report, filename, format="csv"):
    df = pd.DataFrame([report])
    if format == "csv":
        df.to_csv(filename, index=False)
    elif format == "excel":
        df.to_excel(filename, index=False)
    elif format == "json":
        df.to_json(filename, indent=4)
    else:
        raise ValueError("Unsupported format. Use 'csv', 'excel', or 'json'.")

def parse_date_range(period):
    today = datetime.now()
    if period == "month":
        start_date = today.replace(day=1)
        end_date = (start_date + timedelta(days=32)).replace(day=1) - timedelta(days=1)
    elif period == "quarter":
        current_quarter = (today.month - 1) // 3 + 1
        start_date = datetime(today.year, 3 * current_quarter - 2, 1)
        end_date = (start_date + timedelta(days=92)).replace(day=1) - timedelta(days=1)
    elif period == "year":
        start_date = datetime(today.year, 1, 1)
        end_date = datetime(today.year, 12, 31)
    else:
        raise ValueError("Invalid period. Use 'month', 'quarter', or 'year'.")

    return start_date.strftime("%Y-%m-%d"), end_date.strftime("%Y-%m-%d")

def main():
    parser = argparse.ArgumentParser(description="Generate accounting reports for a retail enterprise.")
    parser.add_argument("--report-type", choices=["income_statement", "tax_summary", "cash_flow"], required=True, help="Type of report to generate")
    parser.add_argument("--period", choices=["month", "quarter", "year"], required=True, help="Time period for the report")
    parser.add_argument("--output", default="report", help="Output filename (without extension)")
    parser.add_argument("--format", choices=["csv", "excel", "json"], default="csv", help="Output file format")

    args = parser.parse_args()

    try:
        start_date, end_date = parse_date_range(args.period)
        data = fetch_accounting_data(start_date, end_date)
        report = generate_report(data, args.report_type, args.period)

        filename = f"{args.output}.{args.format}"
        save_report(report, filename, args.format)

        print(f"Report generated successfully: {filename}")

    except Exception as e:
        print(f"Error generating report: {str(e)}", file=sys.stderr)
        sys.exit(1)

if __name__ == "__main__":
    main()

import pandas as pd
from datetime import datetime, timedelta
import sys
from abc import ABC, abstractmethod

# Constants for report types
REPORT_TYPES = {
    "monthly": "Monthly",
    "quarterly": "Quarterly",
    "annual": "Annual"
}

class AccountingDataConnector(ABC):
    """Abstract base class for connecting to accounting systems."""

    @abstractmethod
    def fetch_data(self, start_date, end_date):
        """Fetch accounting data for the given date range."""
        pass

class QuickBooksConnector(AccountingDataConnector):
    """Connector for QuickBooks accounting system."""

    def fetch_data(self, start_date, end_date):
        # Simulate fetching data from QuickBooks
        print(f"Fetching data from QuickBooks for {start_date} to {end_date}")
        # In a real implementation, this would use QuickBooks API
        data = {
            "revenue": 50000.0,
            "expenses": 30000.0,
            "profit": 20000.0,
            "tax": 5000.0
        }
        return data

class SageConnector(AccountingDataConnector):
    """Connector for Sage accounting system."""

    def fetch_data(self, start_date, end_date):
        # Simulate fetching data from Sage
        print(f"Fetching data from Sage for {start_date} to {end_date}")
        # In a real implementation, this would use Sage API
        data = {
            "revenue": 45000.0,
            "expenses": 28000.0,
            "profit": 17000.0,
            "tax": 4000.0
        }
        return data

class ReportGenerator:
    """Generates accounting reports for different periods."""

    def __init__(self, connector: AccountingDataConnector):
        self.connector = connector

    def generate_report(self, report_type, year, month=None, quarter=None):
        """Generate a report for the specified period."""
        if report_type not in REPORT_TYPES:
            raise ValueError(f"Invalid report type. Must be one of: {list(REPORT_TYPES.keys())}")

        start_date, end_date = self._get_date_range(report_type, year, month, quarter)
        data = self.connector.fetch_data(start_date, end_date)

        report = {
            "report_type": REPORT_TYPES[report_type],
            "period": f"{year}-{month if month else ''}{quarter if quarter else ''}",
            "start_date": start_date,
            "end_date": end_date,
            "data": data
        }

        return report

    def _get_date_range(self, report_type, year, month=None, quarter=None):
        """Calculate the start and end dates for the report period."""
        if report_type == "monthly":
            if not month:
                raise ValueError("Month must be specified for monthly reports.")
            start_date = datetime(year, month, 1)
            end_date = (start_date + timedelta(days=32)).replace(day=1) - timedelta(days=1)
        elif report_type == "quarterly":
            if not quarter or quarter not in [1, 2, 3, 4]:
                raise ValueError("Quarter must be specified and be between 1 and 4.")
            start_month = (quarter - 1) * 3 + 1
            start_date = datetime(year, start_month, 1)
            end_date = (start_date + timedelta(days=93)).replace(day=1) - timedelta(days=1)
        elif report_type == "annual":
            start_date = datetime(year, 1, 1)
            end_date = datetime(year, 12, 31)
        else:
            raise ValueError("Invalid report type.")

        return start_date.strftime("%Y-%m-%d"), end_date.strftime("%Y-%m-%d")

    def export_to_csv(self, report, filename):
        """Export the report data to a CSV file."""
        df = pd.DataFrame([report["data"]])
        df["Report Type"] = report["report_type"]
        df["Period"] = report["period"]
        df["Start Date"] = report["start_date"]
        df["End Date"] = report["end_date"]
        df.to_csv(filename, index=False)
        print(f"Report exported to {filename}")

def main():
    # Example usage
    print("Accounting Report Generator")
    print("Supported accounting systems: QuickBooks, Sage")

    # Select accounting system
    accounting_system = input("Enter accounting system (QuickBooks/Sage): ").strip().lower()
    if accounting_system == "quickbooks":
        connector = QuickBooksConnector()
    elif accounting_system == "sage":
        connector = SageConnector()
    else:
        print("Invalid accounting system. Exiting.")
        sys.exit(1)

    generator = ReportGenerator(connector)

    # Select report type
    print("\nSupported report types: monthly, quarterly, annual")
    report_type = input("Enter report type: ").strip().lower()
    year = int(input("Enter year: "))

    month = None
    quarter = None

    if report_type == "monthly":
        month = int(input("Enter month (1-12): "))
    elif report_type == "quarterly":
        quarter = int(input("Enter quarter (1-4): "))

    # Generate report
