import pandas as pd
import datetime
from quickbooks import QuickBooks
from sage50 import Sage50

class FinancialStatementGenerator:
    def __init__(self, accounting_platform="QuickBooks", client_id=None, client_secret=None, company_id=None):
        self.accounting_platform = accounting_platform
        self.client_id = client_id
        self.client_secret = client_secret
        self.company_id = company_id
        self.connection = None
        self.initialize_connection()

    def initialize_connection(self):
        if self.accounting_platform == "QuickBooks":
            self.connection = QuickBooks(
                client_id=self.client_id,
                client_secret=self.client_secret,
                company_id=self.company_id
            )
        elif self.accounting_platform == "Sage":
            self.connection = Sage50(
                company_id=self.company_id
            )
        else:
            raise ValueError("Unsupported accounting platform")

    def fetch_transactions(self, start_date, end_date):
        if self.accounting_platform == "QuickBooks":
            return self.connection.get_transactions(start_date, end_date)
        elif self.accounting_platform == "Sage":
            return self.connection.retrieve_transactions(start_date, end_date)

    def generate_income_statement(self, timeframe="month", custom_start=None, custom_end=None):
        start_date, end_date = self._get_date_range(timeframe, custom_start, custom_end)
        transactions = self.fetch_transactions(start_date, end_date)

        revenue = sum(t['amount'] for t in transactions if t['type'] == 'revenue')
        expenses = sum(t['amount'] for t in transactions if t['type'] == 'expense')
        net_income = revenue - expenses

        statement = {
            "timeframe": f"{start_date} to {end_date}",
            "revenue": revenue,
            "expenses": expenses,
            "net_income": net_income
        }

        return pd.DataFrame([statement])

    def generate_balance_sheet(self, as_of_date=None):
        if not as_of_date:
            as_of_date = datetime.date.today()

        transactions = self.fetch_transactions(datetime.date.min, as_of_date)

        assets = sum(t['amount'] for t in transactions if t['type'] == 'asset')
        liabilities = sum(t['amount'] for t in transactions if t['type'] == 'liability')
        equity = assets - liabilities

        statement = {
            "as_of_date": as_of_date,
            "assets": assets,
            "liabilities": liabilities,
            "equity": equity
        }

        return pd.DataFrame([statement])

    def generate_cash_flow_statement(self, timeframe="month", custom_start=None, custom_end=None):
        start_date, end_date = self._get_date_range(timeframe, custom_start, custom_end)
        transactions = self.fetch_transactions(start_date, end_date)

        operating = sum(t['amount'] for t in transactions if t['category'] == 'operating')
        investing = sum(t['amount'] for t in transactions if t['category'] == 'investing')
        financing = sum(t['amount'] for t in transactions if t['category'] == 'financing')
        net_cash_flow = operating + investing + financing

        statement = {
            "timeframe": f"{start_date} to {end_date}",
            "operating_cash_flow": operating,
            "investing_cash_flow": investing,
            "financing_cash_flow": financing,
            "net_cash_flow": net_cash_flow
        }

        return pd.DataFrame([statement])

    def _get_date_range(self, timeframe, custom_start, custom_end):
        today = datetime.date.today()

        if custom_start and custom_end:
            return custom_start, custom_end

        if timeframe == "month":
            start_date = today.replace(day=1)
            end_date = today
        elif timeframe == "quarter":
            current_quarter = (today.month - 1) // 3 + 1
            start_month = 3 * current_quarter - 2
            start_date = today.replace(month=start_month, day=1)
            end_date = today
        elif timeframe == "year":
            start_date = today.replace(month=1, day=1)
            end_date = today
        else:
            raise ValueError("Invalid timeframe specified")

        return start_date, end_date

    def export_to_excel(self, statements, filename="financial_statements.xlsx"):
        with pd.ExcelWriter(filename) as writer:
            for name, statement in statements.items():
                statement.to_excel(writer, sheet_name=name, index=False)

